import java.io.ByteArrayOutputStream;
import java.util.Scanner;

public class SecureBufferUsage {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Use a dynamic buffer to prevent buffer overflow
        ByteArrayOutputStream buffer = new ByteArrayOutputStream();

        // Copy user input to the dynamic buffer
        buffer.write(userInput.getBytes(), 0, userInput.length());

        System.out.println("Buffer contents: " + new String(buffer.toByteArray()));
    }
}

### Explanation:
취약유형: Buffer Overflow
